  2	import * as React from 'react';
  3	import { useTranslation } from 'react-i18next';
  4	import { Button } from '@patternfly/react-core';
  5	import {
  6	  CompressIcon,
  7	  DownloadIcon,
  8	  ExpandIcon,
  9	} from '@patternfly/react-icons/dist/js/icons';
 10	import { saveAs } from 'file-saver';
 11	import {
 12	  WatchK8sResource,
 13	  useK8sWatchResource,
 14	} from '@openshift-console/dynamic-plugin-sdk';
 15	import { PodKind, TaskRunKind } from '../../types';
 16	import { MultiStreamLogs } from './MultiStreamLogs';
 17	import { TektonTaskRunLog } from './TektonTaskRunLog';
 18	import { useFullscreen } from './fullscreen';
 19	import { LoadingInline } from '../Loading';
 20	import { TektonResourceLabel } from '../../consts';
 21	import { getMultiClusterPods } from '../utils/multi-cluster-api';
 22	import { usePoll } from '../pipelines-metrics/poll-hook';
 23	
 24	type LogsWrapperComponentProps = {
 25	  taskRun: TaskRunKind;
 26	  downloadAllLabel?: string;
 27	  onDownloadAll?: () => Promise<Error | null>;
 28	  resource: WatchK8sResource;
 29	  activeStep?: string;
 30	  isResourceManagedByKueue?: boolean;
 31	  pipelineRunName?: string;
 32	  pipelineRunFinished?: boolean;
 33	};
 34	
 35	const LogsWrapperComponent: React.FC<
 36	  React.PropsWithChildren<LogsWrapperComponentProps>
 37	> = ({
 38	  resource,
 39	  taskRun,
 40	  onDownloadAll,
 41	  downloadAllLabel = 'Download all',
 42	  activeStep,
 43	  isResourceManagedByKueue,
 44	  pipelineRunName,
 45	  pipelineRunFinished,
 46	  ...props
 47	}) => {
 48	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 49	  const resourceRef = React.useRef(null);
 50	
 51	  const k8sResource = isResourceManagedByKueue ? null : resource;
 52	  const [obj, loaded, error] = useK8sWatchResource<PodKind>(k8sResource);
 53	
 54	  // Multi-cluster Pod state for hub clusters
 55	  const [mcPod, setMcPod] = React.useState<PodKind | null>(null);
 56	  const [mcLoaded, setMcLoaded] = React.useState(false);
 57	  const [mcError, setMcError] = React.useState<unknown>(null);
 58	
 59	  /* Fetch Pod from multi-cluster API for hub clusters */
 60	  const fetchMcPod = React.useCallback(async () => {
 61	    if (!isResourceManagedByKueue || !pipelineRunName || !resource?.name || !resource?.namespace) {
 62	      return;
 63	    }
 64	    try {
 65	      const podsResponse = await getMultiClusterPods(
 66	        resource.namespace as string,
 67	        pipelineRunName,
 68	      );
 69	      const pod = podsResponse?.items?.find(
 70	        (p) => p.metadata?.name === resource.name,
 71	      );
 72	      setMcPod(pod);
 73	      if (!pod) {
 74	        /* Simuating k8 api */
 75	        throw new Error('Pod not found in multi-cluster API');
 76	      }
 77	      setMcLoaded(true);
 78	    } catch (e) {
 79	      setMcError(e);
 80	      setMcLoaded(true);
 81	    }
 82	  }, [isResourceManagedByKueue, pipelineRunName, resource?.name, resource?.namespace]);
 83	
 84	  // Poll every 3 seconds while PipelineRun is running, null to disable
 85	  const pollDelay =
 86	    isResourceManagedByKueue && !pipelineRunFinished && pipelineRunName ? 3000 : null;
 87	  usePoll(fetchMcPod, pollDelay, resource?.name, resource?.namespace);
 88	
 89	  const [isFullscreen, fullscreenRef, fullscreenToggle] =
 90	    useFullscreen<HTMLDivElement>();
 91	  const [downloadAllStatus, setDownloadAllStatus] = React.useState(false);
 92	  const currentLogGetterRef = React.useRef<() => string>();
 93	
 94	  const taskName =
 95	    taskRun?.metadata?.labels?.[TektonResourceLabel.pipelineTask] ||
 96	    taskRun?.spec.taskRef?.name ||
 97	    '-';
 98	  const effectiveLoaded = isResourceManagedByKueue ? mcLoaded : loaded;
 99	  const effectiveError = isResourceManagedByKueue ? mcError : error;
100	  const effectiveObj = isResourceManagedByKueue ? mcPod : obj;
101	
102	  if (
103	    effectiveLoaded &&
104	    !effectiveError &&
105	    resource.name === effectiveObj?.metadata?.name
106	  ) {
107	    resourceRef.current = effectiveObj;
108	  } else if (effectiveError) {
109	    resourceRef.current = null;
110	  }
111	
112	  const downloadLogs = () => {
113	    if (!currentLogGetterRef.current) return;
114	    const logString = currentLogGetterRef.current();
115	    const blob = new Blob([logString], {
116	      type: 'text/plain;charset=utf-8',
117	    });
118	    saveAs(blob, `${taskName}.log`);
119	  };
120	  const setLogGetter = React.useCallback(
121	    (getter: any) => (currentLogGetterRef.current = getter),
122	    [],
123	  );
124	
125	  const startDownloadAll = () => {
126	    setDownloadAllStatus(true);
127	    onDownloadAll()
128	      .then(() => {
129	        setDownloadAllStatus(false);
130	      })
131	      .catch((err: Error) => {
132	        setDownloadAllStatus(false);
133	        // eslint-disable-next-line no-console
134	        console.warn(err.message || 'Error downloading logs.');
135	      });
136	  };
137	
138	  return (
139	    <div
140	      ref={fullscreenRef}
141	      className="pf-v6-u-pr-xl pf-v6-u-display-flex pf-v6-u-flex-direction-column pf-v6-u-h-100 pf-v6-u-w-100"
142	    >
143	      <div
144	        className={`pf-v6-l-flex pf-m-gap-md pf-m-align-items-center pf-m-justify-content-flex-end ${
145	          isFullscreen ? 'pf-v5-u-background-color-100 pf-v5-u-p-sm' : ''
146	        }`}
147	      >
148	        <Button variant="link" onClick={downloadLogs} isInline>
149	          <DownloadIcon className="pf-v6-u-mr-xs" />
150	          {t('Download')}
151	        </Button>
152	        <div>|</div>
153	        {onDownloadAll && (
154	          <>
155	            <Button
156	              variant="link"
157	              onClick={startDownloadAll}
158	              isDisabled={downloadAllStatus}
159	              isInline
160	            >
161	              <span className="pf-v6-l-flex pf-m-row pf-m-gap-sm pf-m-align-items-center">
162	                <DownloadIcon />
163	                <span>{downloadAllLabel || t('Download all')}</span>
164	                {downloadAllStatus && <LoadingInline />}
165	              </span>
166	            </Button>
167	            <div>|</div>
168	          </>
169	        )}
170	        {fullscreenToggle && (
171	          <Button variant="link" onClick={fullscreenToggle} isInline>
172	            {isFullscreen ? (
173	              <>
174	                <CompressIcon className="pf-v6-u-mr-xs" />
175	                {t('Collapse')}
176	              </>
177	            ) : (
178	              <>
179	                <ExpandIcon className="pf-v6-u-mr-xs" />
180	                {t('Expand')}
181	              </>
182	            )}
183	          </Button>
184	        )}
185	      </div>
186	      <div className="pf-v6-u-flex-1">
187	        {!effectiveError ? (
188	          <MultiStreamLogs
189	            {...props}
190	            taskName={taskName}
191	            resource={resourceRef.current}
192	            setCurrentLogsGetter={setLogGetter}
193	            activeStep={activeStep}
194	            isResourceManagedByKueue={isResourceManagedByKueue}
195	            pipelineRunName={pipelineRunName}
196	            pipelineRunFinished={pipelineRunFinished}
197	          />
198	        ) : (
199	          <TektonTaskRunLog
200	            taskRun={taskRun}
201	            setCurrentLogsGetter={setLogGetter}
202	          />
203	        )}
204	      </div>
205	    </div>
206	  );
207	};
208	
209	export default LogsWrapperComponent;

